import{_ as t,o,c as n,a3 as a}from"./chunks/framework.CjquFG0V.js";const c=JSON.parse('{"title":"27. Employee Retention","description":"","frontmatter":{"title":"27. Employee Retention","eba":"Mental Health Services 2024-2028","topics":["leave","long-service-leave","employment","preliminary"]},"headers":[],"relativePath":"ebas/mental-health/common-terms/employment-types/27-employee-retention.md","filePath":"ebas/mental-health/common-terms/employment-types/27-employee-retention.md"}'),r={name:"ebas/mental-health/common-terms/employment-types/27-employee-retention.md"};function l(i,e,s,m,p,h){return o(),n("div",null,[...e[0]||(e[0]=[a('<h1 id="_27-employee-retention" tabindex="-1">27. Employee Retention <a class="header-anchor" href="#_27-employee-retention" aria-label="Permalink to &quot;27. Employee Retention&quot;">​</a></h1><p><strong>27.1</strong> An Employer and Employee may agree to the following arrangements to assist in the retention of an Employee. Any of the agreed arrangements below must be established in writing and provided by the Employer to the Employee.</p><p><strong>(a)</strong> An Employer and Employee may agree to allow an Employee to establish an agreed record of accrued long service leave (in hours) that will be preserved and remain available to an Employee should the Employee and the Employer agree that the Employee convert their mode of employment from full time to part time employment to enable retention. This may include an Employee participating in a transition to retirement arrangement in accordance with <a href="/eba/ebas/mental-health/common-terms/employment-types/27A-transition-to-retirement.html">Clause 27A</a> Transition to Retirement.</p><p><strong>(b)</strong> An Employer and Employee may agree to allow an Employee to access additional Purchased leave up to a maximum of 8 weeks in total per calendar year to enable retention. The Purchase leave agreements at <a href="/eba/ebas/mental-health/common-terms/leave/51-purchased-leave.html">clause 51</a> will be followed.</p><p><strong>(c)</strong> An Employer and Employee may agree to allow an Employee to transfer to an alternative work location to facilitate retention.</p><p><strong>27.2</strong> Retention – Community Rotation</p><p><strong>(a)</strong> A senior clinician working in an acute unit, may request a 3-to 6-month rotation to a Mental Health community team. The purpose of this rotation is to retain senior staff, and to further develop skills by working with people who are not in the acute stage.</p><p><strong>(b)</strong> A senior clinician working in a Mental Health Community Team may request a 3-to 6-month rotation to an Acute Inpatient Unit.</p><p><strong>(c)</strong> The rotation is available to senior staff at the level of grade 3 or above.</p><p><strong>(d)</strong> The request at 27.2(a) to 27.2(b) must be in writing and not be unreasonably refused by the Employer</p><p><strong>(e)</strong> An Employee will be classified in accordance with the work being undertaken.</p><p><strong>(f)</strong> No position shall be downgraded as a consequence of this clause</p><p><strong>27.3</strong> Any such agreement shall be established in writing and provided to the Employee by the Employer.</p><p>Plain language terms: retention bonus, keep staff.</p>',14)])])}const d=t(r,[["render",l]]);export{c as __pageData,d as default};
